--
-- Table structure for table `countries`
--

DROP TABLE IF EXISTS `countries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `countries` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'Mã quản lý: Kiểu dữ liệu Integer | Mã tự động tăng | Khóa chính | Không cho phép null | Kiểu Mặc định: Không có',
  `name` varchar(255) NOT NULL COMMENT 'Tên quốc gia: Kiểu dữ liệu string | Size: 255 | Không cho phép null | Kiểu Mặc định: Không có',
  `slug` varchar(255) NOT NULL COMMENT 'Slug: Kiểu dữ liệu string | Size: 255 | Không cho phép null | Kiểu Mặc định: Không có',
  `symbol` varchar(255) DEFAULT NULL COMMENT 'Tên ký hiệu quốc gia: Kiểu dữ liệu string | Size: 255 | Không cho phép null | Kiểu Mặc định: Không có (Vietnam:vn)',
  `official` varchar(255) DEFAULT NULL COMMENT 'Tên đầy đủ của quốc gia (Ngôn ngữ tiếng anh)',
  `nativeName` text DEFAULT NULL COMMENT 'Tên đầy đủ của quốc gia (Ngôn ngữ tiếng việt)',
  `currencies` text DEFAULT NULL COMMENT 'Tiền tệ của quốc gia',
  `capital` varchar(150) DEFAULT NULL COMMENT 'Thủ đô của quốc gia',
  `region` varchar(150) DEFAULT NULL COMMENT 'Lưu tên châu lục của quốc gia',
  `subregion` varchar(150) DEFAULT NULL COMMENT 'Lưu tiêu vùng của quốc gia (vn: Đông Nam Á)',
  `flags` text DEFAULT NULL COMMENT 'Lưu ảnh quốc kỳ của quốc gia',
  `coatOfArms` text DEFAULT NULL COMMENT 'Lưu huy hiệu của quốc gia',
  `phone_area_code` varchar(20) DEFAULT NULL COMMENT 'Lưu mã vùng điện thoại quốc gia',
  `languages` text DEFAULT NULL COMMENT 'Lưu ảnh ngôn ngữ của quốc gia',
  `maps` text DEFAULT NULL COMMENT 'Lưu vị trí trên bản đố',
  `population` int(11) DEFAULT NULL COMMENT 'Lưu thông tin số dân tính tại thời điểm 2023',
  `timezones` varchar(255) DEFAULT NULL COMMENT 'Lưu thông tin timezone của quốc gia',
  `status` tinyint(4) NOT NULL COMMENT 'Trạng thái hoạt động: Kiểu tiny interger chỉ nhận 2 giá trị 0 và 1: O: ngừng hoạt động  |  1: Hoạt động | size: 4 | Not null: Không được phép null  | Kiểu mặc định: 1',
  `created_at` timestamp NULL DEFAULT NULL COMMENT 'Trường thời gian tạo: Kiểu timestamp  | Not null: được phép null  | Kiểu mặc định: Null',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT 'Trường thời gian cập nhật: Kiểu timestamp  | Not null: được phép null  | Kiểu mặc định: Null',
  `deleted_at` datetime DEFAULT NULL COMMENT 'Trường thời gian xóa: Kiểu timestamp  | Not null: được phép null  | Kiểu mặc định: Null',
  `created_by` bigint(20) DEFAULT NULL COMMENT 'Người tạo: Kiểu bigInteger | size: 20  | Not null: được phép null  | Kiểu mặc định: Null',
  `updated_by` bigint(20) DEFAULT NULL COMMENT 'Người cập nhật: Kiểu bigInteger | size: 20  | Not null: được phép null  | Kiểu mặc định: Null',
  `deleted_by` bigint(20) DEFAULT NULL COMMENT 'Người xóa: Kiểu bigInteger | size: 20  | Not null: được phép null  | Kiểu mặc định: Null',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1253 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

